    {
      "id": "determine_sms_message",
      "type": "n8n-nodes-base.code",
      "typeVersion": 1,
      "position": [650, 150],
      "parameters": {
        "language": "javascript",
        "jsCode": "const lead = $input.first().json;
const smsCount24h = lead.sms_count_24h || 0;
const pipelineStep = lead.pipeline_step || 'initial';
const hoursAgo = Math.floor((Date.now() - new Date(lead.last_sms_sent_at).getTime()) / (1000 * 3600));

let message = '';
let priority = 'normal';
let shouldSend = true;

// Determine message based on number of previous SMS and pipeline step
if (smsCount24h === 0) {
  // First follow-up SMS after voicemail
  message = `Hi ${lead.name.split(' ')[0]}! 👋 Following up on your interest in dental care. Quick question—are you looking to do procedures in the next few months? Reply YES or call 1-XXX-DENTAL.`;
} else if (smsCount24h === 1 && hoursAgo >= 4) {
  // Second SMS (4+ hours later) - offer immediate call
  if (lead.lead_score >= 75) {
    message = `${lead.name}, we've got a perfect match for you: ${lead.procedures_interested.split(',')[0]} saves you \$${Math.round(lead.estimated_budget_max * 0.65)}. A specialist will call shortly. Available now? Reply YES.`;
    priority = 'high';
  } else {
    message = `Hi ${lead.name}! Sending over our info about ${lead.procedures_interested.split(',')[0]}. Check your email—link inside to schedule a quick call. Any questions, text back!`;
  }
} else if (smsCount24h >= 2) {
  // Exceeded daily SMS limit
  shouldSend = false;
  priority = 'skip';
}

// If lead has been unresponsive for 48+ hours, escalate instead of SMS
if ((Date.now() - new Date(lead.last_contact_at).getTime()) / (1000 * 3600) > 48) {
  message = 'ESCALATE_TO_EMAIL';
  shouldSend = false;
}

return {
  ...lead,
  sms_message: message,
  sms_priority: priority,
  should_send_sms: shouldSend,
  hours_since_last_sms: hoursAgo
};"

