        "language": "javascript",
        "jsCode": "const body = $input.first().json.body;

// Parse Twilio webhook
const response = {
  phone_number: body.From?.replace('+1', ''),
  message_text: body.Body?.trim() || '',
  message_sid: body.MessageSid || '',
  timestamp: new Date().toISOString()
};

const positiveKeywords = ['yes', 'interested', 'call', 'ready', 'cancel me', 'no thanks', 'not now'];
const messageUpper = response.message_text.toUpperCase();

let sentiment = 'neutral';
if (positiveKeywords.some(kw => messageUpper.includes(kw.toUpperCase()))) {
  if (messageUpper.includes('YES') || messageUpper.includes('INTERESTED') || messageUpper.includes('READY') || messageUpper.includes('CALL')) {
    sentiment = 'positive';
  } else if (messageUpper.includes('NO') || messageUpper.includes('THANKS') || messageUpper.includes('CANCEL')) {
    sentiment = 'negative';
  }
}

return {
  ...response,
  sentiment: sentiment,
  responded: true
};"

